from __future__ import annotations

import hashlib
import json
import os
from pathlib import Path
from typing import Any

from graphify.config import get_cache_dir


def _ensure_cache_dir() -> Path:
    """Create the cache directory if needed and return it."""
    cache_dir = get_cache_dir()
    os.makedirs(cache_dir, exist_ok=True)
    return cache_dir


def file_hash(path: str) -> str:
    """Compute a stable hash for a file path."""
    h = hashlib.sha256()
    with open(path, "rb") as f:
        for chunk in iter(lambda: f.read(8192), b""):
            h.update(chunk)
    return h.hexdigest()


def load_cached(key: str) -> dict[str, Any] | None:
    """Load a cached JSON object by key if it exists."""
    cache_dir = _ensure_cache_dir()
    cache_file = cache_dir / f"{key}.json"
    if not cache_file.exists():
        return None
    try:
        return json.loads(cache_file.read_text(encoding="utf-8"))
    except (OSError, json.JSONDecodeError):
        return None


def save_cached(key: str, data: dict[str, Any]) -> None:
    """Persist a JSON object in the cache."""
    cache_dir = _ensure_cache_dir()
    cache_file = cache_dir / f"{key}.json"
    cache_file.write_text(json.dumps(data), encoding="utf-8")


def cached_files() -> set[str]:
    """Return the set of cached file keys currently on disk."""
    cache_dir = _ensure_cache_dir()
    return {path.stem for path in cache_dir.glob("*.json")}


def clear_cache() -> None:
    """Remove all cached files."""
    cache_dir = _ensure_cache_dir()
    for path in cache_dir.glob("*.json"):
        try:
            path.unlink()
        except OSError:
            pass
