from __future__ import annotations

from collections import defaultdict
from pathlib import Path
from typing import Any, DefaultDict, Iterable, Iterator, Sequence

import networkx as nx


class _DependencyRecord:
    def __init__(self, source: str, target: str, data: dict[str, Any] | None = None) -> None:
        self.source = source
        self.target = target
        self.data = data or {}


def _iter_edges(extraction: dict[str, Any]) -> Iterator[_DependencyRecord]:
    edges = extraction.get("edges", [])
    for edge in edges:
        if isinstance(edge, dict):
            source = edge.get("source") or edge.get("from") or edge.get("src")
            target = edge.get("target") or edge.get("to") or edge.get("dst")
            if source is None or target is None:
                continue
            data = {k: v for k, v in edge.items() if k not in {"source", "target", "from", "to", "src", "dst"}}
            yield _DependencyRecord(str(source), str(target), data)
        elif isinstance(edge, (tuple, list)) and len(edge) >= 2:
            source, target = edge[0], edge[1]
            data: dict[str, Any] = {}
            if len(edge) >= 3 and isinstance(edge[2], dict):
                data = dict(edge[2])
            yield _DependencyRecord(str(source), str(target), data)


def build_graph(extractions: Iterable[dict[str, Any]]) -> nx.DiGraph:
    """Build a directed dependency graph from extracted dependency data.

    Edges that participate in a cycle are marked with ``circular=True``.
    """
    graph = nx.DiGraph()
    for extraction in extractions:
        for node in extraction.get("nodes", []):
            if isinstance(node, dict):
                node_id = node.get("id") or node.get("name")
                if node_id is None:
                    continue
                attrs = {k: v for k, v in node.items() if k not in {"id", "name"}}
                graph.add_node(str(node_id), **attrs)
            else:
                graph.add_node(str(node))

        for dep in _iter_edges(extraction):
            graph.add_edge(dep.source, dep.target, **dep.data)

    _label_circular_edges(graph)
    return graph


def _label_circular_edges(graph: nx.DiGraph) -> None:
    try:
        cycle_edges = set()
        for cycle in nx.simple_cycles(graph):
            if len(cycle) < 2:
                continue
            for i, source in enumerate(cycle):
                target = cycle[(i + 1) % len(cycle)]
                cycle_edges.add((source, target))
        for source, target in cycle_edges:
            if graph.has_edge(source, target):
                graph[source][target]["circular"] = True
    except Exception:
        # Building the graph should still succeed even if cycle detection fails.
        pass


def build_from_files(files: Sequence[str]) -> nx.DiGraph:
    """Build a graph from a sequence of source file paths."""
    from graphify.extract import extract_dependencies

    extractions = []
    for file_path in files:
        path = Path(file_path)
        if not path.exists():
            continue
        extractions.append(extract_dependencies(str(path)))
    return build_graph(extractions)
