from __future__ import annotations

from dataclasses import dataclass
import subprocess
from typing import Optional


@dataclass(frozen=True)
class ScratchpadResult:
    """Result returned from scratchpad execution."""

    stdout: str
    stderr: str
    returncode: int

    @property
    def output(self) -> str:
        """Combined operator-visible output."""

        parts = [part for part in (self.stdout, self.stderr) if part]
        return "\n".join(parts)


class ScratchpadExecutor:
    """Execute scratchpad code and capture its real process output."""

    def execute(self, code: str, *, timeout: Optional[float] = None) -> ScratchpadResult:
        process = subprocess.run(
            ["python", "-c", code],
            capture_output=True,
            text=True,
            timeout=timeout,
            check=False,
        )
        stdout = process.stdout or ""
        stderr = process.stderr or ""
        return ScratchpadResult(stdout=stdout, stderr=stderr, returncode=process.returncode)
